static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Ca6k00301CustomTilingData tiling;

    const gert::StorageShape *x_shape = context->GetInputShape(0);
    const gert::StorageShape *y_shape = context->GetInputShape(1);
    if (x_shape->GetDimNum() != 3 || y_shape->GetDimNum() != 3)
        return ge::GRAPH_FAILED;

    uint32_t batch = x_shape->GetDim(0);
    uint32_t M = x_shape->GetDim(1);
    uint32_t K = x_shape->GetDim(2);
    uint32_t N = y_shape->GetDim(2);

    // auto-compute tile sizes
    // each tile requires: aLocal (tileM * tileK), bLocal (tileK * tileN), cLocal (tileM * tileN)
    // total floats per tile = tileM*tileK + tileK*tileN + tileM*tileN
    // We target 3/4 of UB to leave room for queues.
    uint32_t available = (UB_BUDGET_BYTES * 3 / 4) / sizeof(float);
    uint32_t tileM = 64;
    uint32_t tileN = 64;
    uint32_t tileK = 128;
    // Ensure total < available (safety check)
    while (tileM * tileK + tileK * tileN + tileM * tileN > available && tileM > 16) {
        tileM /= 2; tileN /= 2; tileK /= 2;
    }
    if (tileM < 16) { tileM = 16; tileN = 16; tileK = 16; }

    tiling.batchSize = batch;
    tiling.M = M;
    tiling.N = N;
    tiling.K = K;
    tiling.tileM = tileM;
    tiling.tileK = tileK;
    tiling.tileN = tileN;
    // Use one block per batch
    uint32_t blockDim = batch;
    context->SetBlockDim(blockDim);
    tiling.blockDim = blockDim;

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

